def histogram(test):
    """Given a string representing a space separated lowercase letters, return a dictionary
    of the letter with the most repetition and containing the corresponding count.
    If several letters have the same occurrence, return all of them.

    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    counts = {}
    for char in test.split():
        counts[char] = counts.get(char, 0) + 1
    if not counts:
        return {}
    max_count = max(counts.values())
    return {k: v for k, v in counts.items() if v == max_count}

def split_words(txt):
    '''
    Given a string of words, return a list of words split on whitespace, if no whitespaces exists in the text you
    should split on commas ',' if no commas exists you should return the number of lower-case letters with odd order in the
    alphabet, ord('a') = 0, ord('b') = 1, ... ord('z') = 25
    Examples
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") == 3 
    '''
    if ' ' in txt:
        return txt.split()
    elif ',' in txt:
        return txt.split(',')
    else:
        return sum(1 for c in txt if c.islower() and (ord(c) - ord('a')) % 2 == 1)

def intersection(interval1, interval2):
    start1, end1 = interval1
    start2, end2 = interval2
    intersect_start = max(start1, start2)
    intersect_end = min(end1, end2)

    if intersect_start > intersect_end:
        return "NO"

    length = intersect_end - intersect_start
    if length <= 1:
        return "NO"

    for i in range(2, int(length**0.5) + 1):
        if length % i == 0:
            return "NO"

    return "YES"

def prod_signs(arr):
    if not arr:
        return None
    sum_mags = sum(abs(x) for x in arr)
    sign_product = 1
    for x in arr:
        sign_product *= (1 if x > 0 else -1 if x < 0 else 0)
    return sum_mags * sign_product

def minPath(grid, k):
    N = len(grid)
    start_r, start_c = 0, 0
    for r in range(N):
        for c in range(N):
            if grid[r][c] == 1:
                start_r, start_c = r, c
                break
    path = [1]
    curr_r, curr_c = start_r, start_c
    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    for _ in range(k - 1):
        min_val = float('inf')
        next_r, next_c = curr_r, curr_c
        for dr, dc in directions:
            nr, nc = curr_r + dr, curr_c + dc
            if 0 <= nr < N and 0 <= nc < N:
                val = grid[nr][nc]
                if val < min_val:
                    min_val = val
                    next_r, next_c = nr, nc
        path.append(min_val)
        curr_r, curr_c = next_r, next_c
    return path

